import React, { useState, useEffect, useContext } from 'react';
import {
  Grid,
  Card,
  CardContent,
  Typography,
  Box,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  MenuItem,
  TextField,
  CircularProgress,
} from '@mui/material';
import axios from 'axios';
import { API_URL } from '../utils/apiUrl';
import { AuthContext } from '../context/AuthContext';

export default function SalesReport() {
  const { user } = useContext(AuthContext);
  const [outlets, setOutlets] = useState([]);
  const [selectedOutlet, setSelectedOutlet] = useState('all');
  const [reportData, setReportData] = useState({
    totalRevenue: 0,
    topItems: [],
    recentSales: [],
    outletName: '',
  });
  const [loading, setLoading] = useState(true);

  // ১. ইউজার অনুযায়ী ইনিশিয়াল আউটলেট সেট করা
  useEffect(() => {
    if (user) {
      const initialOutlet = user.role === 'ADMIN' ? 'all' : user.outlet_id;
      setSelectedOutlet(initialOutlet);

      if (user.role === 'ADMIN') {
        axios
          .get(`${API_URL}/api/outlets`)
          .then((res) => setOutlets(res.data.data || []));
      }
    }
  }, [user]);

  // ২. রিপোর্ট ডাটা ফেচ করা
  const fetchReport = async () => {
    try {
      setLoading(true);
      let url = `${API_URL}/api/reports/outlets`;

      // যদি এডমিন সব না দেখে একটা নির্দিষ্ট আউটলেট দেখে অথবা যদি নরমাল ইউজার হয়
      if (selectedOutlet !== 'all') {
        url = `${API_URL}/api/reports/outlets/${selectedOutlet}`;
      }

      const response = await axios.get(url);
      setReportData(response.data); // আপনার এপিআই থেকে আসা ডাটা
    } catch (error) {
      console.error('Report Fetch Error:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (selectedOutlet) fetchReport();
  }, [selectedOutlet]);

  // --- আপনার দেওয়া UI কোডটি এখানে শুরু ---
  return (
    <Box sx={{ p: 3 }}>
      <Box
        sx={{
          display: 'flex',
          justifyContent: 'space-between',
          mb: 3,
          alignItems: 'center',
        }}
      >
        <Typography variant="h4" fontWeight="bold">
          {selectedOutlet === 'all'
            ? 'Global Sales Overview'
            : `Outlet Report: ${reportData.outletName || ''}`}
        </Typography>

        {user?.role === 'ADMIN' && (
          <TextField
            select
            size="small"
            label="Select Outlet"
            value={selectedOutlet}
            onChange={(e) => setSelectedOutlet(e.target.value)}
            sx={{ minWidth: 200 }}
          >
            <MenuItem value="all">🌍 All Outlets (Consolidated)</MenuItem>
            {outlets.map((o) => (
              <MenuItem key={o.id} value={o.id}>
                🏪 {o.name}
              </MenuItem>
            ))}
          </TextField>
        )}
      </Box>

      {loading ? (
        <Box sx={{ display: 'flex', justifyContent: 'center', mt: 5 }}>
          <CircularProgress />
        </Box>
      ) : (
        <Grid container spacing={3}>
          {/* Revenue Card */}
          <Grid item xs={12} md={4}>
            <Card
              sx={{ bgcolor: 'primary.dark', color: 'white', height: '100%' }}
            >
              <CardContent>
                <Typography variant="overline">Total Revenue</Typography>
                <Typography variant="h3">
                  ৳{reportData.totalRevenue?.toLocaleString()}
                </Typography>
              </CardContent>
            </Card>
          </Grid>

          {/* Top Products */}
          <Grid item xs={12} md={8}>
            <Card variant="outlined">
              <CardContent>
                <Typography variant="h6" gutterBottom>
                  🔥 Top Selling Products
                </Typography>
                <Table size="small">
                  <TableHead>
                    <TableRow>
                      <TableCell>Product Name</TableCell>
                      <TableCell align="right">Sold Qty</TableCell>
                      <TableCell align="right">Revenue</TableCell>
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {reportData.topItems?.map((item, idx) => (
                      <TableRow key={idx}>
                        <TableCell>
                          <b>{item.name}</b>
                        </TableCell>
                        <TableCell align="right">{item.total_qty}</TableCell>
                        <TableCell align="right">
                          ৳{item.total_revenue}
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          </Grid>

          {/* Recent Sales List */}
          <Grid item xs={12}>
            <Card variant="outlined">
              <CardContent>
                <Typography variant="h6" gutterBottom>
                  🕒 Recent Transactions
                </Typography>
                <Table>
                  <TableHead sx={{ bgcolor: '#fafafa' }}>
                    <TableRow>
                      <TableCell>Receipt</TableCell>
                      <TableCell>Outlet</TableCell>
                      <TableCell>Customer</TableCell>
                      <TableCell align="right">Amount</TableCell>
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {reportData.recentSales?.map((sale) => (
                      <TableRow key={sale.id}>
                        <TableCell>#{sale.receipt_no}</TableCell>
                        <TableCell>{sale.outlet?.name}</TableCell>
                        <TableCell>
                          {sale.customer?.name || 'Walk-in Customer'}
                        </TableCell>
                        <TableCell align="right">
                          <b>৳{sale.total_amount}</b>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          </Grid>
        </Grid>
      )}
    </Box>
  );
}
